(function(){CKEDITOR.plugins.add("uploadfile",{requires:"uploadwidget,link",init:function(d){if(CKEDITOR.plugins.clipboard.isFileApiSupported){var c=CKEDITOR.fileTools;c.getUploadUrl(d.config)?c.addUploadWidget(d,"uploadfile",{uploadUrl:c.getUploadUrl(d.config),fileToElement:function(e){var b=new CKEDITOR.dom.element("a");b.setText(e.name);b.setAttribute("href","#");return b},onUploaded:function(b){this.replaceWith('\x3ca href\x3d"'+b.url+'" target\x3d"_blank"\x3e'+b.fileName+"\x3c/a\x3e")}}):CKEDITOR.error("uploadfile-config")}}})})();